ReplacementContent:
    // Broadcast the attendance status change (only stu-1 for pat check-in update)
    bc.postMessage({
        type: 'ATTENDANCE_CHANGED',
        studentId: studentId,
        status: status,
        class: document.getElementById('class-select') ? document.getElementById('class-select').value : 'm3',
        room: document.getElementById('room-select') ? document.getElementById('room-select').value : '1'
    });

    updateAttendanceSummary();
}

TargetContent:
    // Broadcast the attendance status change (only stu-1 for pat check-in update)
    bc.postMessage({
        type: 'ATTENDANCE_CHANGED',
        studentId: studentId,
        status: status
    });

    updateAttendanceSummary();
}
